// Tool: get_weather
// The agent passes a query object; read the city it asked about.
const city = (query && (query.city || query.input || query.q)) || '';
if (!city) {
  return 'Please tell me which city you want the weather for.';
}

// 1) Geocode the city name to latitude/longitude (Open-Meteo, no API key).
const geoRes = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://geocoding-api.open-meteo.com/v1/search',
  qs: { name: city, count: 1 },
  json: true,
});

if (!geoRes || !geoRes.results || geoRes.results.length === 0) {
  return `I couldn't find a place called ${city}.`;
}

const place = geoRes.results[0];
const { latitude, longitude, name, country } = place;

// 2) Fetch the current weather for those coordinates.
const wxRes = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.open-meteo.com/v1/forecast',
  qs: { latitude, longitude, current_weather: true },
  json: true,
});

const cw = wxRes && wxRes.current_weather;
if (!cw) {
  return `I couldn't fetch the weather for ${name}.`;
}

// Map Open-Meteo weather codes to short words.
const codes = {
  0: 'clear sky', 1: 'mostly clear', 2: 'partly cloudy', 3: 'overcast',
  45: 'foggy', 48: 'foggy', 51: 'light drizzle', 53: 'drizzle', 55: 'heavy drizzle',
  61: 'light rain', 63: 'rain', 65: 'heavy rain', 71: 'light snow', 73: 'snow',
  75: 'heavy snow', 80: 'rain showers', 81: 'rain showers', 82: 'violent rain showers',
  95: 'thunderstorm', 96: 'thunderstorm with hail', 99: 'severe thunderstorm'
};
const condition = codes[cw.weathercode] || 'unknown conditions';

return `The weather in ${name}, ${country} is ${cw.temperature} degrees Celsius with ${condition} and wind at ${cw.windspeed} km/h.`;

// Tool: create_todo
// Appends the requested task to a todos file on the n8n host.
const fs = require('fs');
const path = require('path');

const task = (query && (query.task || query.todo || query.input)) || '';
if (!task || !String(task).trim()) {
  return 'Please tell me what task to add.';
}

// Folder to store todos. /tmp is writable in most n8n installs.
// Change this path if you want todos saved elsewhere.
const dir = process.env.TODO_DIR || '/tmp/voice-agent';
const file = path.join(dir, 'todos.txt');

try {
  fs.mkdirSync(dir, { recursive: true });
  const stamp = new Date().toISOString();
  const line = `[ ] ${String(task).trim()}  (added ${stamp})\n`;
  fs.appendFileSync(file, line, 'utf8');

  // Count how many todos exist now, for a friendlier reply.
  const count = fs.readFileSync(file, 'utf8').split('\n').filter(Boolean).length;
  return `Added "${String(task).trim()}" to your todo list. You now have ${count} item(s). Saved to ${file}.`;
} catch (err) {
  return `I couldn't save the todo: ${err.message}`;
}
